scwin.onpageload = function() {

    scwin.sDate = $c.date.getServerDateTime("yyyyMMdd");
	scwin.strCurDate = scwin.sDate;
	scwin.strPreDate = scwin.strCurDate.substring(0, 6) + "01";	

    scwin.vCoCd = $c.gus.cfIsNull($c.data.getMemInfo("coCd")) ? '' : $c.data.getMemInfo("coCd"); // 소속 자회사  

    // ?? parent.tabFrame.f_FoldMenu(true);

    const codeOptions = [
        { grpCd : "FS500", compID : "acb_dcsnClsCd" }, 
        { grpCd : "ZZ021", compID : "acb_apprvStsCd" ,opt :{"range" : "1,C"} }, 
        { grpCd : "ZZ022", compID : "acb_apprvDocKndCd" ,opt :{"range" : "1,01"} }, 
    ];
    $c.data.setCommonCode(codeOptions, scwin.commonCodeCallBack);

};

//-------------------------------------------------------------------------
// onUdcCompleted : UDC 완료. 그리는 시점 차이 보완. 
//-------------------------------------------------------------------------
scwin.onUdcCompleted = function() {
    $p.setTimeout(function() {

    }, {"delay":50});
};

scwin.commonCodeCallBack = function(){
    acb_dcsnClsCd.addItem("전체", "", "", 0);
    acb_dcsnClsCd.setSelectedIndex(0);

    acb_apprvStsCd.addItem("전체", "", "", 0);
    acb_apprvStsCd.setSelectedIndex(0);

    acb_apprvDocKndCd.addItem("전체", "", "", 0);
    acb_apprvDocKndCd.setSelectedIndex(0);

    ica_qryConDtFm.setValue(scwin.strPreDate);
    ica_qryConDtTo.setValue(scwin.strCurDate);	
    ica_cancelPostDt.setValue(scwin.strCurDate);
    acb_dcsnClsCd.setValue("4");
    ed_bilgLodeptCd.setValue("8B2");
    ed_bilgLodeptNm.setValue("파주운송");
    acb_delYn.setValue("0");

    $c.gus.cfDisableObjects([
        ed_bilgLodeptCd, ed_bilgLodeptNm
        // udc_bilgLodeptCd
    ]);

    $p.setTimeout(function() {
        // ica_qryConDtFm.setValue("20170817");
        // ica_qryConDtTo.setValue("20170831");

    }, {"delay":50});

};

//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = function () {
    if (acb_qryConKnd.getValue() == "전표번호"){
        if (!$c.gus.cfValidate([ed_slipNo])){
            return;
        }		
    } else {
        if (!$c.gus.cfValidate([ed_bilgLodeptCd,ica_qryConDtFm,ica_qryConDtTo])){
            return;
        }		
    }
    ds_slipList_con.set("bilgLodeptCd", ed_bilgLodeptCd.getValue());
    ds_slipList_con.set("bilgClntNo", ed_bilgClntNo.getValue());
    ds_slipList_con.set("qryConKnd", acb_qryConKnd.getValue());
    ds_slipList_con.set("qryConDtFm", ica_qryConDtFm.getValue());
    ds_slipList_con.set("qryConDtTo", ica_qryConDtTo.getValue());     	
    ds_slipList_con.set("dcsnClsCd", acb_dcsnClsCd.getValue()); 
    ds_slipList_con.set("slipKndCd", acb_slipKndCd.getValue()); 
    ds_slipList_con.set("myModId", ed_modId.getValue());
    ds_slipList_con.set("delYn", acb_delYn.getValue());
    ds_slipList_con.set("slipNo", ed_slipNo.getValue());
    ds_slipList_con.set("offsetNo", acb_offsetNo.getValue());     	
    ds_slipList_con.set("apprvStsCd", acb_apprvStsCd.getValue());
    ds_slipList_con.set("apprvDocKndCd", acb_apprvDocKndCd.getValue());     	     	

    $c.sbm.execute(sbm_slipList_retrieve);

};

//-------------------------------------------------------------------------
// 회계처리취소
//-------------------------------------------------------------------------
scwin.f_CancleSlip = async function (){
    var k = 0;
    for (var i = 0 ; i < ds_slipList.getRowCount() ; i++) {
        if (ds_slipList.getCellData(i, "choice") == "T"){
            if (ds_slipList.getCellData(i, "slipKndCd") != 'K07' 
            && ds_slipList.getCellData(i, "slipKndCd") != 'K08'
            && ds_slipList.getCellData(i, "slipKndCd") != 'K05'
            ){
                await $c.gus.cfAlertMsg("전표종류가 매출,매입,대납금전표인 것만 취소할 수 있습니다.");			
                ds_slipList.setRowPosition(i);
                gr_slipList.setFocusedCell(i, "choice");							
                return;		
            }			
            if (ds_slipList.getCellData(i, "dcsnClsCd") != '4'){
                await $c.gus.cfAlertMsg("확정구분이 전표확정인 것만 취소할 수 있습니다.");			
                ds_slipList.setRowPosition(i);
                gr_slipList.setFocusedCell(i, "choice");						
                return;		
            }
            if (ds_slipList.getCellData(i, "postDt").substring(0, 6) <= ica_slipCloseYm.getValue()){
                var msg = "마감완료된 전표 이므로  역전표 생성 됩니다. 마감기간일 경우 마감이 완전히 끝났는지 확인하시고, 작업하십시요!";
                if (!await $c.win.confirm(msg)){
                    ds_slipList.setRowPosition(i);
                    gr_slipList.setFocusedCell(i, "choice");						
                    return; 
                }	
            }
            if (!scwin.f_CheckTaxCancelSpplyDt(ds_slipList.getCellData(i, "spplyDt"))){
                return;
            } 
            ds_slipList.setCellData(i, "cancelSpplyDt", ica_cancelSpplyDt.getValue());
            k++;
        }
    }
    if (k<1){
        await $c.gus.cfAlertMsg("취소하려는 전표가 선택되지 않았습니다.");
        return;
    }

    // ds_slipList.UseChangeInfo = "false";	
    $c.sbm.execute(sbm_cancelSlip_save);	

};

//-------------------------------------------------------------------------
// 세금계산서 취소 때  세무마감여부 CHECK
//-------------------------------------------------------------------------
scwin.f_CheckTaxCancelSpplyDt = async function (spplyDt){
    var taxCloseYm  = ica_taxCloseYm.getValue();
    var spplyYm		= spplyDt.substring(0,6);
    var isTrue;

    if (taxCloseYm >= spplyYm ) {
        isTrue = await $c.win.confirm("세무마감된 계산서를 취소할 경우에는 반드시 거래처에 수정세금계산서를 발행해야 합니다.(거래처와 합의 요함)\n\n세금계산서 및 전표를 취소하시겠습니까?")

        if (!isTrue) return;

        if ( $c.gus.cfIsNull(ica_cancelSpplyDt.getValue()) ){ 
            await $c.gus.cfAlertMsg(MSG_CM_ERR_002, ["[수정세금계산서 공급일자 ]"]); //@은(는) 필수 입력 항목입니다
            ica_cancelSpplyDt.focus;
            return false;
        }
        if (!$c.gus.cfValidate([ica_cancelSpplyDt])){
            ica_cancelSpplyDt.focus;
            return;
        }
    }
    return true;
};

//-------------------------------------------------------------------------
// 신규
//-------------------------------------------------------------------------
scwin.f_Create = function (){
    ds_slipList.removeAll();
};

//-------------------------------------------------------------------------
// 팝업창 처리
//-------------------------------------------------------------------------
scwin.f_openCommonPopUp = function (disGubun, pCode, pName, pClose, pAllSearch) {
    // 선언부
    var rtnList  = new Array();  // 공통POP-UP -> 요청화면 
    var clntNo   = ed_bilgClntNo.getValue();				
    var param = ","+ scwin.vCoCd;
    switch (disGubun) {
        case 1:
            //청구부서코드팝업		
            udc_bilgLodeptCd.setSelectId('retrieveOpDeptCdInfo');
            udc_bilgLodeptCd.cfCommonPopUp(scwin.udc_bilgLodeptCd_callBackFunc
                                        ,pCode.trim()
                                        ,pName
                                        ,pClose
                                        ,null,null,null,null,null,null,null,null,null,null
                                        ,pAllSearch,null
            );
            break;		

        case 2:
        /*	//청구처코드팝업			
            rtnList = cfCommonPopUp('retrieveClntInfo',pCode.trim(),pName,pClose,null,null,null,null,null,null,null,null,null,null,pAllSearch,null);

            $c.gus.cfSetReturnValue(ref, ed_bilgClntNo, ed_bilgClntNm);  // 청구처코드, 청구처명				
            break;		*/

            sCmdName = "retrieveClntList";
            param    = ",,,"+scwin.vCoCd;
            code = ed_bilgClntNo.getValue();
            name = ed_bilgClntNm.getValue();

            udc_bilgClnt.setSelectId('retrieveClntList');
            udc_bilgClnt.cfCommonPopUp(scwin.udc_bilgClnt_callBackFunc
                                    ,code
                                    ,name
                                    ,'T',
                                    null,null,null,null
                                    ,param
                                    ,null,null,null,null,null
                                    ,"F"
                                    ,null,null
            ); // 거래처
            break;		

        case 3:  		
            // 청구담당자코드 팝업			
            udc_modId.setSelectId('retrieveEmpInfo');
            udc_modId.cfCommonPopUp(scwin.udc_modId_callBackFunc
                                ,pCode.trim()
                                ,pName
                                ,pClose
                                ,null,null,null,null,null,null,null,null,null,null
                                ,pAllSearch,null
            );	  				  			
            break;

        default:
            break;
    }
};

//-------------------------------------------------------------------------
// 팝업 처리시 검색된 데이터인 경우 팝업 처리 안함.
//-------------------------------------------------------------------------
scwin.f_chkOpenCommonPopUp = async function (inObj, pairObj, disGubun, isCode) {

  	// 값이 입력이 안된 경우, 해당 Text Box가 readonly 인 경우, 이전값과 동일한 경우 팝업을 실행하지 않음.
  	if (!await $c.gus.cfCanOpenPopup(inObj, pairObj)) return;

	// 짝이 되는 오브젝트의 값 제거
	$c.gus.cfClearPairObj(pairObj);

	// 검색어 세팅
	var pVal = $c.gus.cfGetValue(inObj);

	// inObj가 코드 필드일 경우 팝업
    if (isCode == null || isCode == true)
	    scwin.f_openCommonPopUp(disGubun, pVal, '', 'T', 'T');
    // inObj가 코드명 필드일 경우 팝업
	else
	    scwin.f_openCommonPopUp(disGubun, '', pVal, 'T', 'T');
};

//-------------------------------------------------------------------------
// 조회조건 Clear
//-------------------------------------------------------------------------
