scwin.f_downExcelSheet = async function (vObjGrd){
    var vObjGrd;
    var sheetTitle;
    var cfrm = await $c.win.confirm("EXCEL로 다운로드 받으시겠습니까?");
    if (cfrm){
        // sheetTitle = "전표 확정 조회 및 취소";			
        // var objGrd = eval(vObjGrd);
        // cfGridToExcel(objGrd, "전표확정 조회 및 취소", "전표확정 조회 및 취소.xls", 4+8+16);
        const infoArr = [];
        const options = {
            fileName : "전표 확정 조회 및 취소.xlsx", //[default : excel.xlsx] options.fileName 값이 없을 경우 default값 세팅
            sheetName: "전표 확정 조회 및 취소",
            type : "1",
            // startRowIndex: 2,
            // removeColumns: "0,21",
            // hiddenVisible : true,
            // useSubTotal :"true", 
            // useSubTotalData  : "true",
            // oddRowBackgroundColor  : "",                        // excel파일에서 그리드 body의 홀수줄의 배경색
            // evenRowBackgroundColor : "#F5FFF5"                  // excel파일에서 그리드 body의 짝수줄의 배경색
        };
        $c.data.downloadGridViewExcel(gr_slipList, options, infoArr);
    }
};	

