scwin.gr_slipList_oncelldblclick = function (row, columnIndex, colid) {
    if (colid == "slipNo" && ds_slipList.getCellData(row, "slipNo") != ""){ 
        $c.gus.cfShowSlipInfo(ds_slipList.getCellData(row, "slipNo"));
    } 
};

scwin.sbm_slipList_retrieve_submit = function (e) {

};

scwin.sbm_slipList_retrieve_submitdone = async function (e) {
    // ds_slipList event=OnLoadCompleted(rowcnt)
	var rowcnt = ds_slipList.getRowCount();
    txt_totalRows.setValue(rowcnt);
	if (rowcnt == 0) {
        ica_slipCloseYm.setValue("");				//회계마감월
	    ica_taxCloseYm.setValue("");					//세무마감월			
		await $c.gus.cfAlertMsg(MSG_CM_WRN_002);
		ed_bilgLodeptCd.focus();

	}else {
        ica_slipCloseYm.setValue(ds_slipList.getCellData(0, "slipCloseYm"));				//회계마감월
	    ica_taxCloseYm.setValue(ds_slipList.getCellData(0, "taxCloseYm"));					//세무마감월
    }

    gr_slipList.setColumnStyle("slipNo", "text-decoration", "underline");
    // gr_dnTrustTaxInvoice.setColumnStyle("button", "color", "blue");
    gr_slipList.setColumnStyle("slipNo", "cursor", "pointer");

};

scwin.sbm_slipList_retrieve_submiterror = function (e) {

};

