    }
};

scwin.sbm_cancelSlip_save_submiterror = function (e) {

};

scwin.acb_qryConKnd_onchange = function (info) {
    if (acb_qryConKnd.getValue() == "전표번호"){
        // div_qryConKnd1
        udc_qryConDt.hide("");
        // div_qryConKnd2
        ed_slipNo.show("");

	} else {
		// div_qryConKnd1
        udc_qryConDt.show("");
        // div_qryConKnd2
        ed_slipNo.hide("");
	}	
};

scwin.udc_bilgLodeptCd_callBackFunc = function(ref){
