scwin.udc_bilgClnt_callBackFunc = function(ref){
    if (ref != null && ref[0] != "N/A"){
        ed_bilgClntNo.setValue(ref[0]);
        ed_bilgClntNm.setValue(ref[1]);
    }
};

scwin.udc_modId_callBackFunc = function(ref){
